import React, { useEffect } from 'react';
import { Link } from 'react-router-dom';
import { updateSeo } from '../../utils/seoHelper';
import styles from './Careers.module.css';
import { FaRocket, FaLaptopCode, FaGlobe, FaSmile, FaMapMarkerAlt, FaBriefcase, FaClock } from 'react-icons/fa';

function Careers() {
  useEffect(() => {
    updateSeo({
      title: 'Careers | Join the Kognivex Engineering Team',
      description: 'We are looking for elite engineers, designers, and product thinkers to build the future of SaaS. Explore open roles at Kognivex.',
    });
  }, []);

  const jobs = [
    {
      id: 1,
      title: "Senior Full-Stack Engineer",
      type: "Full-Time",
      location: "Hyderabad / Remote",
      experience: "5+ Years"
    },
    {
      id: 2,
      title: "UI/UX Product Designer",
      type: "Full-Time",
      location: "Remote",
      experience: "3+ Years"
    },
    {
      id: 3,
      title: "Backend Specialist (Node.js/Python)",
      type: "Full-Time",
      location: "Hyderabad",
      experience: "4+ Years"
    },
    {
      id: 4,
      title: "DevOps & Cloud Architect",
      type: "Contract / Full-Time",
      location: "Remote",
      experience: "6+ Years"
    }
  ];

  return (
    <main className={styles.careersPage}>
      {/* HERO */}
      <section className={styles.hero}>
        <div className={styles.container_hero}>
          <h1>Join the <span>Mission</span></h1>
          <p>
            We are a team of elite engineers and designers building high-performance 
            digital products for global enterprises. Come build the future with us.
          </p>
        </div>
      </section>

      <div className={styles.container}>
        {/* WHY JOIN US */}
        <section className={styles.sectionTitle}>
          <h2>Why Work at Kognivex?</h2>
        </section>

        <div className={styles.benefitsGrid}>
          <div className={styles.benefitCard}>
            <FaLaptopCode />
            <h3>Modern Stack</h3>
            <p>Work with the latest technologies and follow elite engineering standards in every project.</p>
          </div>
          <div className={styles.benefitCard}>
            <FaGlobe />
            <h3>Global Impact</h3>
            <p>Our products are used by enterprises worldwide, solving complex challenges at scale.</p>
          </div>
          <div className={styles.benefitCard}>
            <FaSmile />
            <h3>Culture First</h3>
            <p>We prioritize work-life balance, continuous learning, and a collaborative environment.</p>
          </div>
        </div>

        {/* OPEN POSITIONS */}
        <section className={styles.sectionTitle}>
          <h2>Open Positions</h2>
          <p>Explore our current openings and find your next challenge.</p>
        </section>

        <div className={styles.jobsGrid}>
          {jobs.map((job) => (
            <div key={job.id} className={styles.jobCard}>
              <div className={styles.jobInfo}>
                <h3>{job.title}</h3>
                <div className={styles.jobMeta}>
                  <span><FaMapMarkerAlt /> {job.location}</span>
                  <span><FaBriefcase /> {job.experience}</span>
                  <span><FaClock /> {job.type}</span>
                </div>
              </div>
              <Link to="/contact" className={styles.applyBtn}>Apply Now</Link>
            </div>
          ))}
        </div>
      </div>
    </main>
  );
}

export default Careers;
